async fn fetch_data() -> String {
    // This function returns impl Future<Output = String>
    // The body doesn't run until the future is awaited
    "data".to_string()
}

async fn process() {
    let data = fetch_data().await;  // Runs fetch_data to completion
    println!("Got: {}", data);
}

async fn greet(name: &str) -> String {
    println!("Building greeting...");  // Only prints when awaited
    format!("Hello, {}!", name)
}

async fn demo() {
    let future = greet("Alice");  // Nothing happens yet!
    println!("Future created but not started");
    let result = future.await;     // NOW greet() runs
    println!("{}", result);
}

use std::pin::Pin;
use std::task::{Context, Poll};
use std::future::Future;

// This is what async fn desugars to (conceptually):
struct MyFuture {
    value: String,
}

impl Future for MyFuture {
    type Output = String;

    fn poll(self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<String> {
        // In reality, this would check if work is done
        Poll::Ready(self.value.clone())
    }
}
